package main

import (
	"log"
	"math/rand"
	"net/http"
	"time"

	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promhttp"
)

var (
	requestDuration = prometheus.NewHistogramVec(
		prometheus.HistogramOpts{
			Name:    "http_request_duration_seconds",
			Help:    "Duration of HTTP requests in seconds",
			Buckets: prometheus.DefBuckets,
		},
		[]string{"user_id", "endpoint", "method", "status", "request_id"},
	)

	requestCounter = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "http_requests_total",
			Help: "Total number of HTTP requests",
		},
		[]string{"user_id", "endpoint", "method", "status", "user_agent", "ip_address"},
	)

	activeUsers = prometheus.NewGaugeVec(
		prometheus.GaugeOpts{
			Name: "active_users",
			Help: "Number of active users",
		},
		[]string{"user_id", "session_id", "region", "device_type"},
	)

	dataProcessed = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "data_processed_bytes_total",
			Help: "Total bytes of data processed",
		},
		[]string{"user_id", "operation", "data_type", "source"},
	)

	userOperations = prometheus.NewSummaryVec(
		prometheus.SummaryOpts{
			Name:       "user_operation_duration_seconds",
			Help:       "Duration of user operations",
			Objectives: map[float64]float64{0.5: 0.05, 0.9: 0.01, 0.99: 0.001},
		},
		[]string{"user_id", "operation", "resource_id", "tenant_id"},
	)

	errorCounter = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "errors_total",
			Help: "Total number of errors",
		},
		[]string{"user_id", "error_type", "error_code", "endpoint", "request_id"},
	)
)

func init() {
	prometheus.MustRegister(requestDuration)
	prometheus.MustRegister(requestCounter)
	prometheus.MustRegister(activeUsers)
	prometheus.MustRegister(dataProcessed)
	prometheus.MustRegister(userOperations)
	prometheus.MustRegister(errorCounter)
}

func trackRequest(userID, endpoint, method, status, requestID, userAgent, ipAddress string, duration float64) {
	requestDuration.WithLabelValues(userID, endpoint, method, status, requestID).Observe(duration)
	requestCounter.WithLabelValues(userID, endpoint, method, status, userAgent, ipAddress).Inc()
}

func trackUserActivity(userID, sessionID, region, deviceType string) {
	activeUsers.WithLabelValues(userID, sessionID, region, deviceType).Set(1)
}

func trackDataProcessing(userID, operation, dataType, source string, bytes float64) {
	dataProcessed.WithLabelValues(userID, operation, dataType, source).Add(bytes)
}

func trackUserOperation(userID, operation, resourceID, tenantID string, duration float64) {
	userOperations.WithLabelValues(userID, operation, resourceID, tenantID).Observe(duration)
}

func trackError(userID, errorType, errorCode, endpoint, requestID string) {
	errorCounter.WithLabelValues(userID, errorType, errorCode, endpoint, requestID).Inc()
}

func apiHandler(w http.ResponseWriter, r *http.Request) {
	start := time.Now()

	userID := r.URL.Query().Get("user_id")
	if userID == "" {
		userID = "anonymous"
	}

	endpoint := r.URL.Path
	method := r.Method
	requestID := r.Header.Get("X-Request-ID")
	if requestID == "" {
		requestID = generateRequestID()
	}
	userAgent := r.Header.Get("User-Agent")
	ipAddress := r.RemoteAddr

	sessionID := r.URL.Query().Get("session_id")
	if sessionID == "" {
		sessionID = "default-session"
	}
	region := r.URL.Query().Get("region")
	if region == "" {
		region = "unknown"
	}
	deviceType := r.URL.Query().Get("device_type")
	if deviceType == "" {
		deviceType = "unknown"
	}

	trackUserActivity(userID, sessionID, region, deviceType)

	operation := r.URL.Query().Get("operation")
	if operation == "" {
		operation = "default"
	}
	resourceID := r.URL.Query().Get("resource_id")
	if resourceID == "" {
		resourceID = "none"
	}
	tenantID := r.URL.Query().Get("tenant_id")
	if tenantID == "" {
		tenantID = "default-tenant"
	}

	opStart := time.Now()
	simulateOperation()
	opDuration := time.Since(opStart).Seconds()
	trackUserOperation(userID, operation, resourceID, tenantID, opDuration)

	dataType := r.URL.Query().Get("data_type")
	if dataType == "" {
		dataType = "generic"
	}
	source := r.URL.Query().Get("source")
	if source == "" {
		source = "api"
	}
	bytesProcessed := float64(rand.Intn(10000))
	trackDataProcessing(userID, operation, dataType, source, bytesProcessed)

	status := "200"
	if rand.Float32() < 0.1 {
		status = "500"
		errorType := r.URL.Query().Get("error_type")
		if errorType == "" {
			errorType = "internal_error"
		}
		errorCode := r.URL.Query().Get("error_code")
		if errorCode == "" {
			errorCode = "ERR_500"
		}
		trackError(userID, errorType, errorCode, endpoint, requestID)
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
	} else {
		w.WriteHeader(http.StatusOK)
		w.Write([]byte("Request processed successfully"))
	}

	duration := time.Since(start).Seconds()
	trackRequest(userID, endpoint, method, status, requestID, userAgent, ipAddress, duration)
}

func generateRequestID() string {
	return time.Now().Format("20060102150405") + "-" + randomString(8)
}

func randomString(n int) string {
	const letters = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"
	b := make([]byte, n)
	for i := range b {
		b[i] = letters[rand.Intn(len(letters))]
	}
	return string(b)
}

func simulateOperation() {
	time.Sleep(time.Duration(rand.Intn(100)) * time.Millisecond)
}

func main() {
	rand.Seed(time.Now().UnixNano())

	http.HandleFunc("/api", apiHandler)
	http.Handle("/metrics", promhttp.Handler())

	log.Println("Starting server on :8080")
	log.Println("Metrics available at http://localhost:8080/metrics")
	log.Println("API endpoint at http://localhost:8080/api")
	log.Fatal(http.ListenAndServe(":8080", nil))
}